mapper.select:
SELECT * FROM ( SELECT rownum rn, a.* FROM ( SELECT d.dept_code, d.dept_name, d.dept_tel, d.dept_address AS dept_loc, d.dept_mgr AS dept_mgr, CASE WHEN e.emp_no IS NOT NULL THEN e.emp_name || '(' || e.emp_no || ')' WHEN d.dept_mgr IS NOT NULL THEN TO_CHAR(d.dept_mgr) ELSE NULL END AS dept_mgr_display, d.dept_del_status AS dept_gubun, d.reg_date, TO_CHAR(d.reg_date, 'YYYY-MM-DD') AS str_in_date FROM dept d LEFT JOIN emp e ON e.emp_no = d.dept_mgr AND e.emp_del_status = 0 WHERE d.dept_del_status = 0
AND ( TO_CHAR(d.dept_code) LIKE '%' || #{searchKeyword} || '%' OR d.dept_name LIKE '%' || #{searchKeyword} || '%' )
ORDER BY d.dept_code ) a WHERE rownum <= #{end} ) WHERE rn >= #{start}

mapper.update:
UPDATE dept
SET dept_del_status = 1
WHERE dept_code = #{value}
